import{_ as a,C as d,o as r,c as n,E as i,a3 as s}from"./chunks/framework.BSbon55W.js";const l="/versions/v0.12.0/screens/devices/delay.png",f=JSON.parse('{"title":"Delay","description":"","frontmatter":{"title":"Delay","pageClass":"device-doc"},"headers":[],"relativePath":"devices/delay.md","filePath":"devices/delay.md"}'),h={name:"devices/delay.md"};function o(c,t,g,y,b,u){const e=d("DeviceHeading");return r(),n("div",null,[i(e,{slug:"delay",title:"Delay"}),t[0]||(t[0]=s('<p>Delay notes in time</p><p><img src="'+l+'" alt="Delay parameters" class="screen"></p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Insert <strong>Delay</strong> to <strong>repeat notes in time</strong> with feedback and dry/wet mix — useful for echo effects, MIDI loop shading, or timed re-triggers.</p><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><div class="device-params-table"><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Bypass</td><td>0 – 1</td><td>When on, the device is disabled and MIDI passes through unchanged.</td></tr><tr><td>Delay Time</td><td>0 – 1000</td><td>Time before the first repeat (0–1000 ms or clock-synced).</td></tr><tr><td>Note Length</td><td>0 – 1000</td><td>Length of each delayed note (0–1000 ms).</td></tr><tr><td>Repetitions</td><td>0 – 10</td><td>Number of echo repeats (0–10).</td></tr><tr><td>Feedback</td><td>0 – 100</td><td>Amount fed back into the delay line (0–100%).</td></tr><tr><td>Dry/Wet</td><td>0 – 100</td><td>Balance between original and delayed signal (0–100%).</td></tr><tr><td>Infinite</td><td>0 – 1</td><td>When on, repeats continue until bypassed or reset.</td></tr><tr><td>Sync</td><td>0 – 1</td><td>When on, rate follows MIDI clock; when off, uses async milliseconds.</td></tr><tr><td>Fixed Length</td><td>0 – 1</td><td>When on, delayed notes use Note Length instead of live gate.</td></tr><tr><td>Overdub</td><td>0 – 1</td><td>When on, new input is mixed into the delay buffer while repeats play.</td></tr></tbody></table></div><h2 id="parameter-values" tabindex="-1">Parameter values <a class="header-anchor" href="#parameter-values" aria-label="Permalink to &quot;Parameter values&quot;">​</a></h2><h3 id="bypass" tabindex="-1">Bypass <a class="header-anchor" href="#bypass" aria-label="Permalink to &quot;Bypass&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Device is active and processes MIDI.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Device is bypassed; messages pass through unchanged.</td></tr></tbody></table><h3 id="infinite" tabindex="-1">Infinite <a class="header-anchor" href="#infinite" aria-label="Permalink to &quot;Infinite&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Delay stops after Repetitions.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Echoes continue until bypassed.</td></tr></tbody></table><h3 id="sync" tabindex="-1">Sync <a class="header-anchor" href="#sync" aria-label="Permalink to &quot;Sync&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Free</td><td>Use async time (ms) instead of clock divisions.</td></tr><tr><td style="text-align:right;">1</td><td>Synced</td><td>Step rate follows MIDI clock divisions.</td></tr></tbody></table><h3 id="fixed-length" tabindex="-1">Fixed Length <a class="header-anchor" href="#fixed-length" aria-label="Permalink to &quot;Fixed Length&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Delayed note length follows input gate.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Use Note Length parameter for each repeat.</td></tr></tbody></table><h3 id="overdub" tabindex="-1">Overdub <a class="header-anchor" href="#overdub" aria-label="Permalink to &quot;Overdub&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Input replaces delay buffer content.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Mix new input into running repeats.</td></tr></tbody></table>',17))])}const m=a(h,[["render",o]]);export{f as __pageData,m as default};
